import React, { useState, useEffect } from 'react';
import axios from 'axios';

const UserManagement = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedUser, setSelectedUser] = useState(null);
  const [showEditModal, setShowEditModal] = useState(false);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/users');
      setUsers(res.data);
      setLoading(false);
    } catch (error) {
      console.error('Lỗi tải users:', error);
      setLoading(false);
    }
  };

  const handleRoleChange = async (userId, newRole) => {
    if (window.confirm(`Bạn có chắc muốn thay đổi quyền của user này thành ${newRole}?`)) {
      try {
        await axios.put(`http://localhost:5000/api/admin/users/${userId}/role`, { role: newRole });
        alert('Cập nhật quyền thành công!');
        fetchUsers();
      } catch (error) {
        alert('Lỗi: ' + (error.response?.data?.message || 'Cập nhật thất bại'));
      }
    }
  };

  const handleDeleteUser = async (userId) => {
    if (window.confirm('Bạn có chắc muốn xóa người dùng này?')) {
      try {
        await axios.delete(`http://localhost:5000/api/admin/users/${userId}`);
        alert('Xóa người dùng thành công!');
        fetchUsers();
      } catch (error) {
        alert('Lỗi: ' + (error.response?.data?.message || 'Xóa thất bại'));
      }
    }
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('vi-VN');
  };

  if (loading) return <div className="loading">Đang tải...</div>;

  return (
    <div>
      <h1>Quản lý người dùng</h1>
      
      {/* Thống kê nhanh */}
      <div className="dashboard-stats">
        <div className="stat-card">
          <h3>👥 Tổng users</h3>
          <div className="stat-number">{users.length}</div>
        </div>
        <div className="stat-card">
          <h3>👑 Admin</h3>
          <div className="stat-number">
            {users.filter(u => u.role === 'admin').length}
          </div>
        </div>
        <div className="stat-card">
          <h3>👤 Users</h3>
          <div className="stat-number">
            {users.filter(u => u.role === 'user').length}
          </div>
        </div>
      </div>

      {/* Bảng users */}
      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Họ tên</th>
            <th>Email</th>
            <th>SĐT</th>
            <th>Vai trò</th>
            <th>Ngày tạo</th>
            <th>Thao tác</th>
          </tr>
        </thead>
        <tbody>
          {users.map(user => (
            <tr key={user.id}>
              <td>{user.id}</td>
              <td>
                <strong>{user.fullname}</strong>
              </td>
              <td>{user.email}</td>
              <td>{user.phone || 'Chưa cập nhật'}</td>
              <td>
                <select
                  value={user.role}
                  onChange={(e) => handleRoleChange(user.id, e.target.value)}
                  style={{
                    padding: '5px',
                    borderRadius: '3px',
                    border: '1px solid #ddd',
                    background: user.role === 'admin' ? '#fff3cd' : '#d4edda',
                    color: user.role === 'admin' ? '#856404' : '#155724'
                  }}
                >
                  <option value="user">👤 User</option>
                  <option value="admin">👑 Admin</option>
                </select>
              </td>
              <td>{formatDate(user.created_at)}</td>
              <td>
                <button 
                  onClick={() => handleDeleteUser(user.id)}
                  className="btn-delete"
                  disabled={user.role === 'admin' && users.filter(u => u.role === 'admin').length <= 1}
                  title={user.role === 'admin' && users.filter(u => u.role === 'admin').length <= 1 ? 'Không thể xóa admin cuối cùng' : ''}
                >
                  Xóa
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default UserManagement;
